const csvData = $input.first().json.data;
const lines = csvData.split('\n');
const headers = lines[0].split(',');
const suburbs = lines.slice(1, 4).map(line => {
  const values = line.split(',');
  return {
    suburb: values[0],
    type: values[1],
    median: values[2],
    change: values[3],
    clearance: values[5]
  };
});

const topSuburbs = suburbs.map(s => 
  `<tr><td style='padding:8px;border-bottom:1px solid #1e2d4a;color:#f0ece2'>${s.suburb}</td><td style='padding:8px;border-bottom:1px solid #1e2d4a;color:#c9a84c'>$${parseInt(s.median).toLocaleString()}</td><td style='padding:8px;border-bottom:1px solid #1e2d4a;color:#4ade80'>+${s.change}%</td><td style='padding:8px;border-bottom:1px solid #1e2d4a;color:#f0ece2'>${s.clearance}%</td></tr>`
).join('');

